26	    public function getClaimList(array $filters = []): LengthAwarePaginator
27	    {
28	        $query = BpjsClaim::with(['visit.patient', 'visit.insurer']);
29	
30	        if (! empty($filters['status'])) {
31	            $query->where('status', $filters['status']);
32	        }
33	
34	        if (! empty($filters['search'])) {
35	            $keyword = $filters['search'];
36	            $query->where(fn ($q) => $q
37	                ->where('no_sep', 'like', "%{$keyword}%")
38	                ->orWhere('patient_nik', 'like', "%{$keyword}%")
39	                ->orWhereHas('visit.patient', fn ($p) => $p->where('name', 'ilike', "%{$keyword}%"))
40	            );
41	        }
42	
43	        if (! empty($filters['tanggal_from'])) {
44	            $query->whereDate('created_at', '>=', $filters['tanggal_from']);
45	        }
46	
47	        if (! empty($filters['tanggal_to'])) {
48	            $query->whereDate('created_at', '<=', $filters['tanggal_to']);
49	        }
50	
51	        return $query->orderByDesc('created_at')->paginate($filters['per_page'] ?? 20);
52	    }
