68	    /**
69	     * Create or update BpjsClaim from visit doctor examination data.
70	     * Source: visit.no_sep, doctorExamination.{diagnosis_utama, diagnosis_sekunder, tindakan_codes}
71	     */
72	    public function prepareClaimData(string $visitId): BpjsClaim
73	    {
74	        $visit = Visit::with([
75	            'patient',
76	            'doctorExamination',
77	            'billingInvoice',
78	        ])->findOrFail($visitId);
79	
80	        if ($visit->guarantor_type !== 'BPJS') {
81	            throw new \Exception('Kunjungan bukan pasien BPJS.', 422);
82	        }
83	
84	        if (empty($visit->no_sep)) {
85	            throw new \Exception('Nomor SEP belum ada — generate SEP terlebih dahulu di Admisi.', 422);
86	        }
87	
88	        $exam = $visit->doctorExamination;
89	
90	        if (! $exam?->diagnosis_utama) {
91	            throw new \Exception('Diagnosis utama belum diisi oleh Dokter.', 422);
92	        }
93	
94	        $user = auth('api')->user();
95	
96	        $claim = DB::transaction(function () use ($visit, $exam, $user) {
97	            $existing = BpjsClaim::where('visit_id', $visit->id)->first();
98	            $oldStatus = $existing?->status;
99	
100	            $claim = BpjsClaim::updateOrCreate(
101	                ['visit_id' => $visit->id],
102	                [
103	                    'no_sep'             => $visit->no_sep,
104	                    'patient_nik'        => $visit->patient->nik,
105	                    'diagnosis_utama'    => $exam->diagnosis_utama,
106	                    'diagnosis_sekunder' => $exam->diagnosis_sekunder ?? [],
107	                    'procedure_codes'    => $exam->tindakan_codes ?? [],
108	                    'status'             => $existing?->status ?? 'DRAFT',
109	                ]
110	            );
111	
112	            $this->addAuditLog(
113	                $claim->id,
114	                $user->employee_id,
115	                'PREPARE',
116	                $oldStatus,
117	                $claim->status,
118	                'Data klaim disiapkan dari data kunjungan'
119	            );
120	
121	            return $claim;
122	        });
123	
124	        $this->log($user->id, 'PREPARE_CLAIM', BpjsClaim::class, $claim->id, "SEP {$visit->no_sep}");
125	
126	        return $claim->fresh(['visit.patient', 'auditLogs.performedBy']);
127	    }
