133	    /**
134	     * Run INA-CBGs grouper on claim data → get CBG code + tariff + severity.
135	     * Placeholder: actual engine is JAR-based or API-based (configured per year).
136	     */
137	    public function runInaCbgsGrouping(string $claimId): BpjsClaim
138	    {
139	        $claim = BpjsClaim::findOrFail($claimId);
140	
141	        if (in_array($claim->status, ['SUBMITTED', 'SELESAI'])) {
142	            throw new \Exception('Klaim sudah disubmit, tidak bisa grouping ulang.', 422);
143	        }
144	
145	        if (! $claim->diagnosis_utama) {
146	            throw new \Exception('Diagnosis utama belum ada.', 422);
147	        }
148	
149	        $config    = $this->getInaCbgsConfig();
150	        $inputData = [
151	            'diagnosis_utama'    => $claim->diagnosis_utama,
152	            'diagnosis_sekunder' => $claim->diagnosis_sekunder ?? [],
153	            'procedure_codes'    => $claim->procedure_codes ?? [],
154	        ];
155	
156	        // Run grouper (placeholder — integrasikan JAR/API saat engine tersedia)
157	        $result = $this->callGrouper($inputData, $config);
158	
159	        return DB::transaction(function () use ($claim, $inputData, $result, $config) {
160	            $user = auth('api')->user();
161	
162	            // Simpan grouping log
163	            InacbgsGroupingLog::create([
164	                'visit_id'        => $claim->visit_id,
165	                'bpjs_claim_id'   => $claim->id,
166	                'grouper_version' => $config['version'] ?? self::GROUPER_VERSION,
167	                'input_diagnosis' => [
168	                    'utama'    => $inputData['diagnosis_utama'],
169	                    'sekunder' => $inputData['diagnosis_sekunder'],
170	                ],
171	                'input_tindakan'  => array_map(fn ($c) => ['code' => $c], $inputData['procedure_codes']),
172	                'cbg_code'        => $result['cbg_code'],
173	                'cbg_tarif'       => $result['cbg_tarif'],
174	                'severity_level'  => $result['severity_level'],
175	                'engine_type'     => $config['engine_type'] ?? 'JAR',
176	                'status'          => $result['success'] ? 'SUCCESS' : 'FAILED',
177	                'error_message'   => $result['error'] ?? null,
178	            ]);
179	
180	            if (! $result['success']) {
181	                throw new \Exception('Grouper gagal: ' . ($result['error'] ?? 'Unknown error'), 500);
182	            }
183	
184	            $oldStatus = $claim->status;
185	
186	            $claim->update([
187	                'inacbgs_kode' => $result['cbg_code'],
188	                'inacbgs_tarif' => $result['cbg_tarif'],
189	            ]);
190	
191	            $this->addAuditLog(
192	                $claim->id,
193	                $user->employee_id,
194	                'GROUPING',
195	                $oldStatus,
196	                $claim->status,
197	                "CBG: {$result['cbg_code']} — Tarif: " . number_format($result['cbg_tarif'])
198	            );
199	
200	            return $claim;
201	        });
202	    }
