208	    public function generateLupis(string $claimId): BpjsClaim
209	    {
210	        $claim = BpjsClaim::with(['visit.patient', 'visit.billingInvoice.items'])->findOrFail($claimId);
211	
212	        if (! $claim->inacbgs_kode) {
213	            throw new \Exception('Jalankan INA-CBGs grouping terlebih dahulu sebelum generate LUPIS.', 422);
214	        }
215	
216	        $visit   = $claim->visit;
217	        $patient = $visit->patient;
218	
219	        // LUPIS format (struktur sesuai spesifikasi BPJS)
220	        $lupisData = [
221	            'noSep'            => $claim->no_sep,
222	            'nik'              => $claim->patient_nik,
223	            'nama'             => $patient->name,
224	            'tglLahir'         => $patient->date_of_birth?->format('Y-m-d'),
225	            'jnsPelayanan'     => '2', // 2 = rawat jalan
226	            'diagnosaUtama'    => $claim->diagnosis_utama,
227	            'diagnosaSekunder' => $claim->diagnosis_sekunder ?? [],
228	            'procedureCodes'   => $claim->procedure_codes ?? [],
229	            'cbgCode'          => $claim->inacbgs_kode,
230	            'cbgTarif'         => $claim->inacbgs_tarif,
231	            'totalBiaya'       => $visit->billingInvoice?->total ?? 0,
232	            'tglPulang'        => $visit->updated_at?->format('Y-m-d'),
233	        ];
234	
235	        $user = auth('api')->user();
236	
237	        $claim->update(['lupis_data' => $lupisData]);
238	
239	        $this->addAuditLog($claim->id, $user->employee_id, 'LUPIS_GENERATED', $claim->status, $claim->status);
240	        $this->log($user->id, 'GENERATE_LUPIS', BpjsClaim::class, $claimId);
241	
242	        return $claim->fresh();
243	    }
