426	        string $action
427	    ): BpjsClaim {
428	        $claim = BpjsClaim::findOrFail($claimId);
429	        $user  = auth('api')->user();
430	
431	        if ($claim->status !== $fromStatus) {
432	            throw new \Exception("Klaim harus dalam status {$fromStatus} untuk tindakan ini.", 422);
