435	        $claim->update(['status' => $toStatus]);
436	
437	        $this->addAuditLog($claim->id, $user->employee_id, $action, $fromStatus, $toStatus);
438	        $this->log($user->id, $action . '_CLAIM', BpjsClaim::class, $claimId, "{$fromStatus} → {$toStatus}");
