3	namespace App\Services;
4	
5	use App\Models\BpjsVClaimLog;
6	use App\Services\Bpjs\BpjsClient;
7	
8	/**
9	 * BPJS VClaim — REST API VClaim (vclaim-rest-dev / vclaim-rest).
10	 *
11	 * Semua call dilakukan lewat {@see BpjsClient} (auth HMAC + decrypt AES/LZString).
12	 * Response VClaim terenkripsi → BpjsClient::request($m,$p,$body, encrypted: true).
13	 *
14	 * Cakupan (Docs/BRIDGING VCLAIM.md):
15	 *   Peserta, Rujukan (cari/insert/update/delete + 2.0 + list keluar + spesialistik/sarana),
16	 *   SEP 2.0 (insert/update/delete/updtglplg + internal + fingerprint + cbg),
17	 *   Surat Kontrol / Rencana Kontrol v2 / SPRI, LPK, Monitoring, Referensi.
18	 *
19	 * Konvensi return: array hasil BpjsClient → { metaData, response, http_status, is_success, raw }.
20	 * Bila integrasi belum aktif → BpjsClient melempar RuntimeException(503) — caller menangani.
21	 */
22	class BpjsVClaimService
23	{
24	    private BpjsClient $client;
25	
26	    public function __construct(?BpjsClient $client = null)
27	    {
28	        $this->client = $client ?? BpjsClient::for('VCLAIM');
29	    }
30	
31	    public function boot(): void
32	    {
33	        // Kompat lama: re-resolve client (membaca ulang config dari DB).
34	        $this->client = BpjsClient::for('VCLAIM');
35	    }
36	
37	    public function isEnabled(): bool
38	    {
39	        return $this->client->isEnabled();
40	    }
41	
42	    // =========================================================================
43	    // PESERTA
44	    // =========================================================================
45	
46	    /**
47	     * GET /Peserta/nokartu/{no}/tglSEP/{tgl}  atau  /Peserta/nik/{nik}/tglSEP/{tgl}
48	     *
49	     * @param  string  $type  'nokartu' | 'nik'
50	     */
51	    public function checkPeserta(string $identifier, string $type = 'nik', string $tglSep = '', ?string $visitId = null): array
52	    {
53	        $type   = strtolower($type) === 'nokartu' ? 'nokartu' : 'nik';
54	        $tglSep = $tglSep ?: now('Asia/Jakarta')->toDateString();
55	
56	        $result = $this->client->request('GET', "/Peserta/{$type}/{$identifier}/tglSEP/{$tglSep}");
57	
58	        $this->log($visitId, 'CHECK_PESERTA', compact('identifier', 'type', 'tglSep'), $result);
59	
60	        return $result;
61	    }
62	
63	    // =========================================================================
64	    // RUJUKAN
65	    // =========================================================================
66	
67	    /** GET /Rujukan/RS/{noRujukan} — cari rujukan masuk (FKRTL) by nomor. */
68	    public function checkRujukan(string $noRujukan, ?string $visitId = null): array
69	    {
70	        $result = $this->client->request('GET', "/Rujukan/RS/{$noRujukan}");
71	        $this->log($visitId, 'CHECK_RUJUKAN', compact('noRujukan'), $result);
72	
73	        return $result;
74	    }
75	
76	    /** GET /Rujukan/{noRujukan} — cari rujukan FKTP (faskes 1) by nomor. */
77	    public function checkRujukanFktp(string $noRujukan, ?string $visitId = null): array
78	    {
79	        $result = $this->client->request('GET', "/Rujukan/{$noRujukan}");
80	        $this->log($visitId, 'CHECK_RUJUKAN_FKTP', compact('noRujukan'), $result);
81	
82	        return $result;
83	    }
84	
85	    /** GET /Rujukan/RS/Peserta/{noKartu} — rujukan terakhir (1 record). */
86	    public function getRujukanByKartu(string $noKartu): array
87	    {
88	        return $this->client->request('GET', "/Rujukan/RS/Peserta/{$noKartu}");
89	    }
90	
91	    /** GET /Rujukan/RS/List/Peserta/{noKartu} — semua rujukan (multi record). */
92	    public function listRujukanByKartu(string $noKartu): array
93	    {
94	        return $this->client->request('GET', "/Rujukan/RS/List/Peserta/{$noKartu}");
95	    }
96	
97	    /** POST /Rujukan/2.0/insert — buat rujukan keluar. */
98	    public function insertRujukanKeluar(array $tRujukan, ?string $visitId = null): array
99	    {
100	        $result = $this->client->request('POST', '/Rujukan/2.0/insert', ['request' => ['t_rujukan' => $tRujukan]]);
101	        $this->log($visitId, 'INSERT_RUJUKAN', $tRujukan, $result);
102	
103	        return $result;
104	    }
