445	    private function refCached(string $path, string $key, int $ttl = 1800): array
446	    {
447	        return \Illuminate\Support\Facades\Cache::remember(
448	            "bpjs:vclaim:ref:{$key}",
449	            $ttl,
450	            fn () => $this->client->request('GET', $path)
451	        );
452	    }
