478	
479	    private function log(?string $visitId, string $action, array $request, array $result): void
480	    {
481	        // response BPJS bisa scalar (mis. nomor SEP) — bungkus agar cast 'array' aman.
482	        $response = $result['response'] ?? null;
483	        if (! is_array($response)) {
484	            $response = ['metaData' => $result['metaData'] ?? null, 'response' => $response];
485	        }
486	
487	        BpjsVClaimLog::create([
488	            'visit_id'         => $visitId,
489	            'action'           => $action,
490	            'request_payload'  => $request,
491	            'response_payload' => $response,
492	            'http_status'      => $result['http_status'] ?? 0,
493	            'is_success'       => $result['is_success'] ?? false,
494	            'error_message'    => ($result['is_success'] ?? false) ? null : ($result['metaData']['message'] ?? null),
495	        ]);
496	    }
