450	    /**
451	     * Tariff lookup by insurer (post drop_classification).
452	     *
453	     * Resolve order:
454	     *   1. Pakai visit.insurer_id (resolve TPA: child → parent via tariffInsurerId()).
455	     *   2. Bila NULL → resolve insurer sistem dari guarantor_type (UMUM/BPJS/SOSIAL).
456	     *   3. Fallback: insurer sistem UMUM.
457	     */
458	    public function getPrice(string $itemType, ?string $itemId, string $guarantorType, ?string $insurerId): float
459	    {
460	        if (! $itemId) {
461	            return 0;
462	        }
463	
464	        [$table, $fkColumn] = match ($itemType) {
465	            'procedure'       => ['procedure_tariffs',            'procedure_id'],
466	            'medication'      => ['medication_tariffs',           'medication_id'],
467	            'bhp'             => ['bhp_tariffs',                  'bhp_item_id'],
468	            'iol'             => ['iol_tariffs',                  'iol_item_id'],
469	            'equipment'       => ['medical_equipment_tariffs',    'medical_equipment_id'],
470	            default           => throw new \Exception("Item type tidak dikenal: {$itemType}", 422),
471	        };
472	
473	        $resolvedInsurerId = $this->resolveTariffInsurerId($insurerId, $guarantorType);
474	        if (! $resolvedInsurerId) {
475	            return 0;
476	        }
477	
478	        $baseQuery = DB::table($table)
479	            ->where($fkColumn, $itemId)
480	            ->where('is_active', true);
481	
482	        // Level 1: insurer terpilih (sudah di-resolve TPA parent).
483	        $tariff = (clone $baseQuery)->where('insurer_id', $resolvedInsurerId)->value('price');
484	        if ($tariff !== null) {
485	            return (float) $tariff;
486	        }
487	
488	        // Level 2: fallback ke insurer sistem UMUM.
489	        $umumId = $this->systemInsurerId('UMUM');
490	        if ($umumId && $umumId !== $resolvedInsurerId) {
491	            $tariff = (clone $baseQuery)->where('insurer_id', $umumId)->value('price');
492	            if ($tariff !== null) {
493	                return (float) $tariff;
494	            }
495	        }
496	
497	        return 0;
498	    }
499	
500	    /**
501	     * Resolve insurer_id untuk lookup tarif. Mengembalikan parent_id bila child TPA,
502	     * atau insurer sistem (UMUM/BPJS/SOSIAL) bila visit belum di-link ke insurer eksplisit.
503	     */
504	    private function resolveTariffInsurerId(?string $insurerId, string $guarantorType): ?string
505	    {
506	        if ($insurerId) {
507	            $insurer = Insurer::find($insurerId);
508	            if ($insurer) {
509	                return $insurer->tariffInsurerId();
510	            }
511	        }
512	
513	        return $this->systemInsurerId(in_array($guarantorType, ['UMUM', 'BPJS', 'SOSIAL'], true) ? $guarantorType : 'UMUM');
514	    }
