516	    /** Cache id insurer sistem (UMUM/BPJS/SOSIAL) untuk hindari query berulang. */
517	    private array $systemInsurerCache = [];
518	    private function systemInsurerId(string $type): ?string
519	    {
520	        if (! array_key_exists($type, $this->systemInsurerCache)) {
521	            $this->systemInsurerCache[$type] = Insurer::where('is_system', true)->where('type', $type)->value('id');
522	        }
523	        return $this->systemInsurerCache[$type];
524	    }
