567	    public function updateInvoice(string $id, array $data): BillingInvoice
568	    {
569	        $invoice = BillingInvoice::findOrFail($id);
570	
571	        if (in_array($invoice->status, ['PAID', 'CANCELLED'])) {
572	            throw new \Exception('Invoice sudah lunas atau dibatalkan, tidak bisa diubah.', 422);
573	        }
574	
575	        $patch = array_filter([
576	            'discount'         => $data['discount']         ?? null,
577	            'discount_percent' => $data['discount_percent'] ?? null,
578	            'tax'              => $data['tax']              ?? null,
579	            'notes'            => $data['notes']            ?? null,
580	        ], fn ($v) => ! is_null($v));
581	
582	        // Bila user kirim discount_percent → hitung discount nominal dari subtotal-after-item-discount
583	        if (isset($patch['discount_percent']) && ! isset($patch['discount'])) {
584	            $itemDiscount   = (float) $invoice->items()->sum('discount_amount');
585	            $subtotalAfter  = max(0, (float) $invoice->subtotal - $itemDiscount);
586	            $patch['discount'] = round($subtotalAfter * ((float) $patch['discount_percent']) / 100, 2);
587	        }
588	
589	        $invoice->update($patch);
590	
591	        $this->recalculateInvoice($invoice);
592	
593	        $this->log(auth('api')->id(), 'UPDATE_INVOICE', BillingInvoice::class, $id);
594	
595	        return $invoice->fresh(['items']);
596	    }
