707	    /**
708	     * Kirim LPK ke VClaim untuk kunjungan BPJS yang sudah punya no_sep.
709	     * Membentuk t_lpk dari diagnosa & tindakan dokter. Non-blocking total.
710	     */
711	    private function maybeSubmitLpkBpjs(?string $visitId): void
712	    {
713	        try {
714	            if (! $visitId) {
715	                return;
716	            }
717	            $visit = \App\Models\Visit::with(['doctorExamination', 'doctorSchedule.employee'])->find($visitId);
718	            if (! $visit || $visit->guarantor_type !== 'BPJS' || empty($visit->no_sep)) {
719	                return;
720	            }
721	
722	            $vclaim = app(\App\Services\BpjsVClaimService::class);
723	            if (! $vclaim->isEnabled()) {
724	                return;
725	            }
726	
727	            $exam     = $visit->doctorExamination;
728	            $kodePoli = \App\Models\BpjsPoliMapping::bpjsCodeFor($visit->doctorSchedule?->poli_code);
729	            $kodeDpjp = $visit->doctorSchedule?->employee?->bpjs_dpjp_code;
730	
731	            // Diagnosa: utama (level 1) + sekunder (level 2).
732	            $diagnosa = [];
733	            if ($exam?->diagnosis_utama) {
734	                $diagnosa[] = ['kode' => $exam->diagnosis_utama, 'level' => '1'];
735	            }
736	            foreach ((array) ($exam?->diagnosis_sekunder ?? []) as $kode) {
737	                if ($kode) $diagnosa[] = ['kode' => $kode, 'level' => '2'];
738	            }
739	
740	            // Procedure: ICD-9 dari tindakan_codes.
741	            $procedure = array_values(array_filter(array_map(
742	                fn ($k) => $k ? ['kode' => $k] : null,
743	                (array) ($exam?->tindakan_codes ?? [])
744	            )));
745	
746	            // Diagnosa wajib minimal 1 — kalau dokter belum isi, skip (tidak kirim LPK kosong).
747	            if (empty($diagnosa)) {
748	                return;
749	            }
750	
751	            $today = now('Asia/Jakarta')->toDateString();
752	            $vclaim->insertLpk([
753	                'noSep'      => $visit->no_sep,
754	                'tglMasuk'   => $today,
755	                'tglKeluar'  => $today,
756	                'jaminan'    => '1',
757	                'poli'       => ['poli' => $kodePoli ?? ''],
758	                'perawatan'  => ['ruangRawat' => '', 'kelasRawat' => '', 'spesialistik' => '', 'caraKeluar' => '1', 'kondisiPulang' => '1'],
759	                'diagnosa'   => $diagnosa,
760	                'procedure'  => $procedure,
761	                'rencanaTL'  => ['tindakLanjut' => '1', 'dirujukKe' => ['kodePPK' => ''], 'kontrolKembali' => ['tglKontrol' => '', 'poli' => '']],
762	                'DPJP'       => $kodeDpjp ?? '',
763	                'user'       => auth('api')->user()?->name ?? 'arumed',
764	            ], $visit->id);
765	        } catch (\Throwable $e) {
766	            \Illuminate\Support\Facades\Log::warning('BPJS LPK gagal: ' . $e->getMessage());
767	        }
768	    }
