60	     * Called by: app/Console/Kernel.php or Laravel Scheduler
61	     */
62	    public function batchSync(string $syncType = 'AUTO'): SatusehatSyncLog
63	    {
64	        $this->assertEnabled();
65	
66	        $syncLog = SatusehatSyncLog::create([
67	            'sync_date'    => today(),
68	            'sync_type'    => $syncType,
69	            'status'       => 'RUNNING',
70	            'total_sent'   => 0,
71	            'total_failed' => 0,
72	            'retry_count'  => 0,
73	        ]);
74	
75	        try {
76	            // Visit SELESAI hari ini yg belum/ gagal sync. PENDING|FAILED dikelompokkan
77	            // dgn benar (where bersarang) agar filter tanggal+station tidak bocor.
78	            $visits = Visit::whereIn('satusehat_sync_status', ['PENDING', 'FAILED'])
79	                ->whereDate('visit_date', today())
80	                ->where('current_station', 'SELESAI')
81	                ->with(['patient', 'doctorExamination.doctor', 'prescriptions.items.medication', 'prescriptions.prescribedBy', 'prescriptions.dispensedBy'])
82	                ->get();
83	
84	            $sent   = 0;
85	            $failed = 0;
86	
87	            foreach ($visits as $visit) {
88	                $result = $this->syncVisit($visit, $syncLog->id);
89	                $result ? $sent++ : $failed++;
90	            }
91	
92	            $status = match (true) {
93	                $failed === 0            => 'SUCCESS',
94	                $sent === 0             => 'FAILED',
95	                default                  => 'PARTIAL',
96	            };
97	
98	            $syncLog->update([
99	                'status'       => $status,
100	                'total_sent'   => $sent,
101	                'total_failed' => $failed,
102	                'next_retry_at' => $status !== 'SUCCESS'
103	                    ? now()->addHours(2)->setTime(1, 0)
104	                    : null,
105	            ]);
106	        } catch (\Throwable $e) {
107	            $syncLog->update(['status' => 'FAILED']);
108	        }
109	
110	        return $syncLog->fresh();
111	    }
