117	    /**
118	     * Sync satu visit via FHIR transaction Bundle (Encounter+Condition+obat).
119	     * Delegasi ke {@see syncVisitBundle} — jalur tunggal yg terbukti (4 statistik).
120	     * Status visit di-update di dalam syncVisitBundle (SYNCED/FAILED + encounter_id).
121	     */
122	    public function syncVisit(Visit $visit, ?string $syncLogId = null): bool
123	    {
124	        try {
125	            $result = $this->syncVisitBundle($visit, $syncLogId);
126	        } catch (\Throwable $e) {
127	            $visit->forceFill(['satusehat_sync_status' => 'FAILED'])->save();
128	            return false;
129	        }
130	
131	        return (bool) ($result['is_success'] ?? false);
132	    }
