138	    /**
139	     * POST /fhir-r4/Encounter. Idempoten: kalau visit sudah punya
140	     * satusehat_encounter_id → skip POST, kembalikan id lama. Saat sukses,
141	     * simpan id ke visits.satusehat_encounter_id.
142	     */
143	    public function sendEncounter(Visit $visit): array
144	    {
145	        if (! empty($visit->satusehat_encounter_id)) {
146	            return ['is_success' => true, 'id' => $visit->satusehat_encounter_id, 'skipped' => true];
147	        }
148	
149	        $result = $this->postFhir('Encounter', $this->buildEncounterPayload($visit), $visit->id);
150	
151	        if (($result['is_success'] ?? false) && ! empty($result['id'])) {
152	            $visit->forceFill(['satusehat_encounter_id' => $result['id']])->save();
153	        }
154	
155	        return $result;
156	    }
