158	    /**
159	     * POST semua Condition visit (utama + sekunder). Mengembalikan ringkasan
160	     * { is_success (semua sukses), sent, results[] }.
161	     */
162	    public function sendCondition(Visit $visit): array
163	    {
164	        $payloads = $this->buildConditionPayloads($visit);
165	        $results  = [];
166	        $allOk    = true;
167	
168	        foreach ($payloads as $payload) {
169	            $r = $this->postFhir('Condition', $payload, $visit->id);
170	            $results[] = $r;
171	            $allOk = $allOk && ($r['is_success'] ?? false);
172	        }
173	
174	        return ['is_success' => $allOk && count($payloads) > 0, 'sent' => count($payloads), 'results' => $results];
175	    }
